const BRIDGE_LENGTH = 600;
const DECK_WIDTH = 14;
const DECK_Y = 5;
const PYLON_HEIGHT = 50;
const PYLON_POSITIONS = [-100, 100]; // X positions of the two main towers
const CABLES_PER_SIDE = 12;

